mapper.select:
SELECT /* @SQLID=FCT030#Sql002 */ C.BROKER_CODE, C.BROKER_CHARGE_CODE FROM ( SELECT #{req.privId} "PRIVILEGE_ID" FROM DUAL WHERE #{req.privId} IN ('6','7','8') ) A INNER JOIN( SELECT BROKER_BRANCH_KIND FROM MEDIATE_BRANCH WHERE BROKER_CODE=#{req.brokerCode} AND BROKER_BRANCH_CODE=#{req.subBrokerCode} AND BROKER_BRANCH_KIND='00' ) B ON 1=1 INNER JOIN( SELECT G.BROKER_CODE, G.BROKER_CHARGE_CODE FROM MEDIATE_CHARGE_INFO G INNER JOIN( SELECT BROKER_ID, SUB_BROKER_ID FROM TB_MED_USERS WHERE USER_ID=#{req.userId} UNION SELECT BROKER_ID, SUB_BROKER_ID FROM TB_MED_USERS_PRIV WHERE USER_ID=#{req.userId}
) H ON G.BROKER_CODE=H.BROKER_ID ) C ON 1=1 UNION SELECT F.BROKER_CODE, F.BROKER_CHARGE_CODE FROM ( SELECT #{req.privId} "PRIVILEGE_ID" FROM DUAL WHERE #{req.privId} IN ('6','7','8') ) D INNER JOIN( SELECT BROKER_BRANCH_KIND FROM MEDIATE_BRANCH WHERE BROKER_CODE=#{req.brokerCode} AND BROKER_BRANCH_CODE=#{req.subBrokerCode} AND BROKER_BRANCH_KIND!='00' ) E ON 1=1 INNER JOIN( SELECT I.BROKER_CODE, I.BROKER_CHARGE_CODE FROM MEDIATE_CHARGE_INFO I INNER JOIN( SELECT BROKER_ID, SUB_BROKER_ID FROM TB_MED_USERS WHERE USER_ID=#{req.userId} UNION SELECT BROKER_ID, SUB_BROKER_ID FROM TB_MED_USERS_PRIV WHERE USER_ID=#{req.userId}
) J ON I.BROKER_CODE=J.BROKER_ID AND I.BROKER_BRANCH_CODE=J.SUB_BROKER_ID ) F ON 1=1

SELECT /* @SQLID=FCT030#Sql003 */ C.BROKER_ID AS BROKER_CODE, NULL AS BROKER_CHARGE_CODE FROM ( SELECT #{req.privId} "PRIVILEGE_ID" FROM DUAL WHERE #{req.privId} IN ('3','4','5') ) A INNER JOIN( SELECT BROKER_BRANCH_KIND FROM MEDIATE_BRANCH WHERE BROKER_CODE=#{req.brokerCode} AND BROKER_BRANCH_KIND='00' ) B ON 1=1 INNER JOIN( SELECT BROKER_ID FROM TB_MED_USERS WHERE USER_ID=#{req.userId}
UNION
SELECT BROKER_ID FROM TB_MED_USERS_PRIV WHERE USER_ID=#{req.userId} ) C ON 1=1
